//! Report generation engine — orchestrates research, LLM, and formatting.
//!
//! Pipeline: load → research → synthesize → generate → format → store.
//! Research and LLM calls are in engine_research.rs.

use convergio_db::pool::ConnPool;
use serde_json::json;

use crate::engine_research::{build_generation_prompt, build_search_queries, call_inference};
use crate::template;
use crate::types::{ReportStatus, ReportType};

const AGENT_ID: &str = "ctt-report-engine";

/// Run the full report generation pipeline for a given report ID.
pub async fn generate(pool: &ConnPool, report_id: &str) {
    tracing::info!(report_id, "CTT report generation starting");

    let row = match load_report(pool, report_id) {
        Some(r) => r,
        None => {
            tracing::error!(report_id, "report not found");
            return;
        }
    };

    let report_type: ReportType =
        serde_json::from_value(json!(row.report_type_str)).unwrap_or(ReportType::General);
    let date = template::report_date();

    // Phase 1: Research
    update_status(pool, report_id, ReportStatus::Researching);
    let research = run_research(pool, report_id, &row.topic, report_type).await;

    // Phase 2: Generate via LLM
    update_status(pool, report_id, ReportStatus::Generating);
    let content = run_generation(
        &row.topic,
        report_type,
        &date,
        &row.depth,
        row.audience.as_deref(),
        row.extra_context.as_deref(),
        &research,
    )
    .await;

    // Phase 3: PDF compilation (if requested)
    let pdf_path = if row.format_str == "pdf" {
        update_status(pool, report_id, ReportStatus::Compiling);
        let report_type: ReportType =
            serde_json::from_value(json!(row.report_type_str)).unwrap_or(ReportType::General);
        let latex_content =
            crate::latex::markdown_to_latex(&content, &row.topic, report_type, &date);
        let slug = crate::latex::topic_slug(&row.topic);
        let filename = format!("ctt-{slug}-{}", chrono::Utc::now().format("%Y%m%d"));
        let output_dir = std::path::PathBuf::from("/tmp/ctt-reports");
        match crate::pdf_compiler::compile_pdf(&latex_content, &output_dir, &filename) {
            Ok(path) => {
                tracing::info!(report_id, ?path, "PDF compiled");
                Some(path.to_string_lossy().to_string())
            }
            Err(e) => {
                tracing::warn!(report_id, error = %e, "PDF compilation failed, markdown still saved");
                None
            }
        }
    } else {
        None
    };

    // Phase 4: Store result
    let word_count = content.split_whitespace().count();
    let section_count = content.matches("\n## ").count();
    let metadata = json!({
        "word_count": word_count,
        "section_count": section_count,
        "source_count": 0,
        "format": row.format_str,
        "depth": row.depth,
        "pdf_compiled": pdf_path.is_some(),
    });

    save_content(pool, report_id, &content, &metadata.to_string());
    if let Some(ref path) = pdf_path {
        save_pdf_path(pool, report_id, path);
    }
    update_status(pool, report_id, ReportStatus::Completed);
    tracing::info!(report_id, word_count, "CTT report generation complete");
}

async fn run_research(
    _pool: &ConnPool,
    report_id: &str,
    topic: &str,
    report_type: ReportType,
) -> String {
    let queries = build_search_queries(topic, report_type);
    let mut research_parts = Vec::new();

    for query in &queries {
        let prompt = format!(
            "Search the web for: {query}\n\
             Return factual, well-sourced information. Include URLs where available."
        );
        match call_inference(&prompt, AGENT_ID).await {
            Ok(result) if !result.is_empty() => {
                research_parts.push(result);
            }
            Ok(_) => {
                tracing::debug!(query, "empty research result");
            }
            Err(e) => {
                tracing::warn!(query, error = %e, "research query failed");
            }
        }
    }

    if research_parts.is_empty() {
        tracing::warn!(report_id, "no research data gathered — using topic only");
        format!("Topic: {topic}. No additional research data available.")
    } else {
        research_parts.join("\n\n---\n\n")
    }
}

async fn run_generation(
    topic: &str,
    report_type: ReportType,
    date: &str,
    depth: &str,
    audience: Option<&str>,
    extra_context: Option<&str>,
    research: &str,
) -> String {
    let prompt =
        build_generation_prompt(topic, report_type, depth, audience, extra_context, research);

    let llm_content = match call_inference(&prompt, AGENT_ID).await {
        Ok(content) if !content.is_empty() => content,
        Ok(_) | Err(_) => {
            tracing::warn!("LLM generation failed, using fallback template");
            fallback_content(topic, report_type, date)
        }
    };

    // Wrap with CTT branding
    let mut md = template::format_header(topic, report_type, date);
    md.push_str(&llm_content);
    md.push_str(&template::format_sources(&[]));
    md.push_str(&template::format_disclaimer());
    md.push_str(&template::format_footer(topic, date));
    md
}

fn fallback_content(topic: &str, report_type: ReportType, _date: &str) -> String {
    format!(
        "## Executive Summary\n\n\
         This {label} report on **{topic}** was generated by {brand}. \
         The inference service was unavailable during generation; \
         this is a structural template that will be populated when \
         the service is restored.\n\n\
         ## Key Takeaways\n\n\
         1. Report infrastructure is operational.\n\
         2. CTT branding and disclaimer applied.\n\
         3. Full research-backed content pending inference availability.\n\n",
        label = report_type.label(),
        brand = template::CTT_BRAND,
    )
}

// --- DB helpers ---

struct ReportRow {
    topic: String,
    report_type_str: String,
    format_str: String,
    depth: String,
    audience: Option<String>,
    extra_context: Option<String>,
}

fn load_report(pool: &ConnPool, report_id: &str) -> Option<ReportRow> {
    let conn = pool.get().ok()?;
    conn.query_row(
        "SELECT topic, report_type, format, depth, audience, extra_context \
         FROM reports WHERE id = ?1",
        rusqlite::params![report_id],
        |r| {
            Ok(ReportRow {
                topic: r.get(0)?,
                report_type_str: r.get(1)?,
                format_str: r.get(2)?,
                depth: r.get(3)?,
                audience: r.get(4)?,
                extra_context: r.get(5)?,
            })
        },
    )
    .ok()
}

fn update_status(pool: &ConnPool, report_id: &str, status: ReportStatus) {
    if let Ok(conn) = pool.get() {
        let status_str = status.to_string();
        let _ = conn.execute(
            "UPDATE reports SET status = ?1 WHERE id = ?2",
            rusqlite::params![status_str, report_id],
        );
    }
}

fn save_content(pool: &ConnPool, report_id: &str, content: &str, metadata: &str) {
    if let Ok(conn) = pool.get() {
        let _ = conn.execute(
            "UPDATE reports SET content_md = ?1, metadata_json = ?2, \
             completed_at = datetime('now') WHERE id = ?3",
            rusqlite::params![content, metadata, report_id],
        );
    }
}

fn save_pdf_path(pool: &ConnPool, report_id: &str, pdf_path: &str) {
    if let Ok(conn) = pool.get() {
        let _ = conn.execute(
            "UPDATE reports SET pdf_path = ?1 WHERE id = ?2",
            rusqlite::params![pdf_path, report_id],
        );
    }
}

//! Research and LLM synthesis — the intelligence behind CTT reports.
//!
//! Handles: building search queries, calling inference API,
//! assembling the CTT prompt template, and parsing LLM output.

use serde_json::json;

use crate::types::ReportType;

const DAEMON_URL: &str = "http://localhost:8420";

/// Build web-search queries for the research phase based on topic and type.
pub fn build_search_queries(topic: &str, report_type: ReportType) -> Vec<String> {
    let base = vec![
        format!("{topic} overview latest news"),
        format!("{topic} key facts statistics"),
    ];
    let specific = match report_type {
        ReportType::LeadershipProfile => vec![
            format!("{topic} career background biography"),
            format!("{topic} achievements awards recognition"),
            format!("{topic} leadership impact contributions"),
        ],
        ReportType::CompanyDeepDive => vec![
            format!("{topic} company revenue financials"),
            format!("{topic} strategy leadership CEO"),
            format!("{topic} competitive landscape market position"),
        ],
        ReportType::IndustryAnalysis => vec![
            format!("{topic} industry market size trends"),
            format!("{topic} key players market share"),
            format!("{topic} regulatory landscape challenges"),
        ],
        ReportType::TechAnalysis => vec![
            format!("{topic} technology capabilities features"),
            format!("{topic} adoption market competitors"),
            format!("{topic} roadmap future developments"),
        ],
        ReportType::MarketReport => vec![
            format!("{topic} market trends economic factors"),
            format!("{topic} growth forecast projections"),
            format!("{topic} risks opportunities investors"),
        ],
        ReportType::General => vec![
            format!("{topic} analysis research findings"),
            format!("{topic} trends developments recent"),
        ],
    };
    [base, specific].concat()
}

/// Call the inference API to perform research for a single query.
pub async fn call_inference(prompt: &str, agent_id: &str) -> Result<String, String> {
    let client = reqwest::Client::new();
    let body = json!({
        "prompt": prompt,
        "max_tokens": 2048,
        "tier_hint": "t1",
        "agent_id": agent_id,
        "org_id": "convergio.io",
        "constraints": {}
    });

    let resp = client
        .post(format!("{DAEMON_URL}/api/inference/complete"))
        .json(&body)
        .send()
        .await
        .map_err(|e| format!("inference request failed: {e}"))?;

    if !resp.status().is_success() {
        return Err(format!("inference returned {}", resp.status()));
    }

    let val: serde_json::Value = resp.json().await.map_err(|e| e.to_string())?;
    // Response shape: { "response": { "content": "..." }, "decision": {...} }
    let content = val
        .pointer("/response/content")
        .or_else(|| val.get("content"))
        .and_then(|v| v.as_str())
        .unwrap_or("")
        .to_string();
    Ok(content)
}

/// Build the full CTT generation prompt from research data.
pub fn build_generation_prompt(
    topic: &str,
    report_type: ReportType,
    depth: &str,
    audience: Option<&str>,
    extra_context: Option<&str>,
    research_data: &str,
) -> String {
    let depth_instruction = match depth {
        "brief" => "Keep it concise: 3-5 pages equivalent, executive summary focus.",
        "standard" => "Standard depth: 8-12 pages equivalent, balanced analysis.",
        "full" => "Full depth: 15-25 pages equivalent, comprehensive deep-dive.",
        _ => "Standard depth.",
    };

    let audience_line = audience
        .map(|a| format!("Target audience: {a}."))
        .unwrap_or_default();
    let context_line = extra_context
        .map(|c| format!("Additional context: {c}."))
        .unwrap_or_default();

    format!(
        "You are the Convergio Think Tank (CTT) report generator.\n\
         Generate a professional {type_label} on: {topic}\n\n\
         {audience_line}\n{context_line}\n{depth_instruction}\n\n\
         ## Research Data\n{research_data}\n\n\
         ## Output Format (Morgan Stanley methodology)\n\
         Write the report in Markdown with these sections:\n\
         1. Executive Summary (2-3 dense paragraphs)\n\
         2. Key Takeaways (5-7 bullet points)\n\
         3. Deep Analysis (2-4 thematic sections with data)\n\
         4. KPI Dashboard (table with key metrics)\n\
         5. What Worked / Areas to Monitor (structured pro/contra)\n\
         6. Sources & Methodology\n\n\
         ## Rules\n\
         - Every claim must reference the research data provided.\n\
         - Use confidence indicators: [Verified], [Reported], [Uncertain].\n\
         - If data is unavailable, say 'Data not available' — never fabricate.\n\
         - Include a Data Cutoff Date section.\n\
         - Be professional, precise, and data-driven.\n",
        type_label = report_type.label(),
    )
}

//! Extension trait implementation for convergio-reports.

use std::sync::Arc;

use convergio_db::pool::ConnPool;
use convergio_types::extension::{AppContext, Extension, Health, McpToolDef, Metric, Migration};
use convergio_types::manifest::{Capability, Manifest, ModuleKind};

use crate::routes::{reports_routes, ReportsState};

pub struct ReportsExtension {
    pool: ConnPool,
}

impl ReportsExtension {
    pub fn new(pool: ConnPool) -> Self {
        Self { pool }
    }

    fn state(&self) -> Arc<ReportsState> {
        Arc::new(ReportsState {
            pool: self.pool.clone(),
        })
    }
}

impl Extension for ReportsExtension {
    fn manifest(&self) -> Manifest {
        Manifest {
            id: "convergio-reports".to_string(),
            description: "Convergio Think Tank — professional report generation service"
                .to_string(),
            version: env!("CARGO_PKG_VERSION").to_string(),
            kind: ModuleKind::Extension,
            provides: vec![
                Capability {
                    name: "reports".to_string(),
                    version: "1.0.0".to_string(),
                    description: "CTT research report generation".to_string(),
                },
                Capability {
                    name: "reports-api".to_string(),
                    version: "1.0.0".to_string(),
                    description: "REST API for report CRUD and generation".to_string(),
                },
            ],
            requires: vec![],
            agent_tools: vec![],
            required_roles: vec!["orchestrator".into(), "all".into()],
        }
    }

    fn routes(&self, _ctx: &AppContext) -> Option<axum::Router> {
        Some(reports_routes(self.state()))
    }

    fn migrations(&self) -> Vec<Migration> {
        vec![Migration {
            version: 1,
            description: "reports table",
            up: "CREATE TABLE IF NOT EXISTS reports (\
                    id TEXT PRIMARY KEY,\
                    org_id TEXT NOT NULL DEFAULT 'convergio.io',\
                    topic TEXT NOT NULL,\
                    report_type TEXT NOT NULL,\
                    format TEXT NOT NULL DEFAULT 'markdown',\
                    status TEXT NOT NULL DEFAULT 'pending',\
                    audience TEXT,\
                    depth TEXT NOT NULL DEFAULT 'standard',\
                    content_md TEXT,\
                    pdf_path TEXT,\
                    sources_json TEXT,\
                    metadata_json TEXT,\
                    extra_context TEXT,\
                    error TEXT,\
                    created_at TEXT NOT NULL DEFAULT (datetime('now')),\
                    completed_at TEXT\
                );\
                CREATE INDEX IF NOT EXISTS idx_reports_org \
                    ON reports(org_id);\
                CREATE INDEX IF NOT EXISTS idx_reports_status \
                    ON reports(status);\
                CREATE INDEX IF NOT EXISTS idx_reports_type \
                    ON reports(report_type);",
        }]
    }

    fn health(&self) -> Health {
        match self.pool.get() {
            Ok(_) => Health::Ok,
            Err(e) => Health::Degraded {
                reason: format!("db: {e}"),
            },
        }
    }

    fn metrics(&self) -> Vec<Metric> {
        let count: f64 = self
            .pool
            .get()
            .ok()
            .and_then(|c| {
                c.query_row("SELECT COUNT(*) FROM reports", [], |r| r.get::<_, i64>(0))
                    .ok()
            })
            .unwrap_or(0) as f64;
        vec![Metric {
            name: "reports_total".to_string(),
            value: count,
            labels: vec![],
        }]
    }

    fn mcp_tools(&self) -> Vec<McpToolDef> {
        crate::mcp_defs::reports_tools()
    }
}

//! LaTeX template for CTT PDF report generation.
//!
//! Converts Markdown report content to a professional LaTeX document
//! with Morgan Stanley-inspired design: custom colors, headers/footers,
//! booktabs tables, and CTT branding.

use crate::template::{CTT_BRAND, CTT_SHORT, DISCLAIMER};
use crate::types::ReportType;

/// LaTeX preamble with CTT styling.
fn preamble(topic: &str, report_type: ReportType, date: &str) -> String {
    format!(
        r#"\documentclass[11pt,a4paper]{{article}}
\usepackage[utf8]{{inputenc}}
\usepackage[T1]{{fontenc}}
\usepackage{{lmodern}}
\usepackage[margin=1in]{{geometry}}
\usepackage{{xcolor}}
\usepackage{{fancyhdr}}
\usepackage{{titlesec}}
\usepackage{{booktabs}}
\usepackage{{hyperref}}
\usepackage{{enumitem}}
\usepackage{{tabularx}}

% CTT Colors (Morgan Stanley inspired)
\definecolor{{msblue}}{{HTML}}{{003366}}
\definecolor{{msgray}}{{HTML}}{{666666}}
\definecolor{{msgreen}}{{HTML}}{{006633}}
\definecolor{{msred}}{{HTML}}{{CC0000}}
\definecolor{{mslightgray}}{{HTML}}{{F5F5F5}}

% Section formatting
\titleformat{{\section}}{{\Large\bfseries\color{{msblue}}}}{{}}{{0em}}{{}}
\titleformat{{\subsection}}{{\large\bfseries\color{{msblue!80}}}}{{}}{{0em}}{{}}
\titleformat{{\subsubsection}}{{\normalsize\bfseries\color{{msgray}}}}{{}}{{0em}}{{}}

% Header/Footer
\pagestyle{{fancy}}
\fancyhf{{}}
\fancyhead[L]{{\small\color{{msblue}}\textbf{{{brand}}} | {label}}}
\fancyhead[R]{{\small\color{{msgray}}{date}}}
\fancyfoot[L]{{\small\color{{msgray}}{short} | {topic} | CONFIDENTIAL}}
\fancyfoot[R]{{\small\color{{msgray}}Page \thepage}}
\renewcommand{{\headrulewidth}}{{0.4pt}}
\renewcommand{{\footrulewidth}}{{0.4pt}}

% Hyperlinks
\hypersetup{{colorlinks=true,linkcolor=msblue,urlcolor=msblue,citecolor=msblue}}

\begin{{document}}
"#,
        brand = CTT_BRAND,
        short = CTT_SHORT,
        label = report_type.label(),
    )
}

/// Convert Markdown content to LaTeX body.
pub fn markdown_to_latex(
    content_md: &str,
    topic: &str,
    report_type: ReportType,
    date: &str,
) -> String {
    let mut latex = preamble(topic, report_type, date);

    // Title page
    latex.push_str(&format!(
        r#"\begin{{center}}
\vspace*{{2cm}}
{{\Huge\bfseries\color{{msblue}} {brand}}}\\[0.5cm]
{{\Large\color{{msgray}} {label}}}\\[1cm]
{{\large\textbf{{Subject:}} {topic}}}\\[0.3cm]
{{\large\textbf{{Report Date:}} {date}}}\\[0.3cm]
{{\large\textbf{{Data Cutoff:}} {date}}}\\[2cm]
{{\small\color{{msgray}} CONFIDENTIAL}}
\end{{center}}
\newpage
\tableofcontents
\newpage
"#,
        brand = CTT_BRAND,
        label = report_type.label(),
    ));

    // Convert Markdown body to LaTeX
    for line in content_md.lines() {
        latex.push_str(&convert_md_line(line));
        latex.push('\n');
    }

    // Disclaimer page
    latex.push_str(&format!(
        r#"
\newpage
\section*{{Disclaimer}}
\small
{disclaimer}
"#,
        disclaimer = latex_escape(DISCLAIMER),
    ));

    latex.push_str("\\end{document}\n");
    latex
}

/// Convert a single Markdown line to LaTeX.
fn convert_md_line(line: &str) -> String {
    if line.starts_with("# ") {
        String::new()
    } else if let Some(rest) = line.strip_prefix("## ") {
        format!("\\section{{{}}}", latex_escape(rest))
    } else if let Some(rest) = line.strip_prefix("### ") {
        format!("\\subsection{{{}}}", latex_escape(rest))
    } else if let Some(rest) = line.strip_prefix("#### ") {
        format!("\\subsubsection{{{}}}", latex_escape(rest))
    } else if let Some(rest) = line.strip_prefix("- ").or_else(|| line.strip_prefix("* ")) {
        format!("\\item {}", latex_escape(rest))
    } else if let Some(rest) = line.strip_prefix("> ") {
        format!(
            "\\begin{{quote}}\\textit{{{}}}\\end{{quote}}",
            latex_escape(rest)
        )
    } else if line.starts_with("---") {
        "\\vspace{0.5em}\\hrule\\vspace{0.5em}".to_string()
    } else if line.is_empty() {
        String::from("\n")
    } else {
        latex_escape(line)
    }
}

/// Escape special LaTeX characters.
fn latex_escape(text: &str) -> String {
    text.replace('\\', r"\textbackslash{}")
        .replace('&', r"\&")
        .replace('%', r"\%")
        .replace('$', r"\$")
        .replace('#', r"\#")
        .replace('_', r"\_")
        .replace('{', r"\{")
        .replace('}', r"\}")
        .replace('~', r"\textasciitilde{}")
        .replace('^', r"\textasciicircum{}")
}

/// Generate the output filename slug.
pub fn topic_slug(topic: &str) -> String {
    topic
        .to_lowercase()
        .chars()
        .map(|c| if c.is_alphanumeric() { c } else { '-' })
        .collect::<String>()
        .trim_matches('-')
        .to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn preamble_contains_colors() {
        let p = preamble("Test", ReportType::General, "01 Jan 2026");
        assert!(p.contains("msblue"));
        assert!(p.contains("003366"));
        assert!(p.contains(CTT_BRAND));
    }

    #[test]
    fn markdown_to_latex_has_structure() {
        let md = "## Summary\nHello world\n### Details\nMore info";
        let latex = markdown_to_latex(md, "Test", ReportType::General, "01 Jan 2026");
        assert!(latex.contains(r"\section{Summary}"));
        assert!(latex.contains(r"\subsection{Details}"));
        assert!(latex.contains(r"\end{document}"));
        assert!(latex.contains("Disclaimer"));
    }

    #[test]
    fn latex_escape_special_chars() {
        assert_eq!(latex_escape("a & b"), r"a \& b");
        assert_eq!(latex_escape("100%"), r"100\%");
        assert_eq!(latex_escape("$10"), r"\$10");
    }

    #[test]
    fn topic_slug_formats_correctly() {
        assert_eq!(topic_slug("Dedalus Group"), "dedalus-group");
        assert_eq!(topic_slug("Roberto D'Angelo"), "roberto-d-angelo");
    }
}

//! convergio-reports — Convergio Think Tank (CTT) report generation service.
//!
//! Professional research reports: leadership profiles, company deep-dives,
