    vec![
        McpToolDef {
            name: "cvg_generate_report".into(),
            description: "Generate a CTT research report on a given topic.".into(),
            method: "POST".into(),
            path: "/api/reports/generate".into(),
            input_schema: json!({
                "type": "object",
